import fs from 'fs';
import path from 'path';
import { execSync } from 'child_process';

function walkDir(dir, callback) {
  fs.readdirSync(dir).forEach(f => {
    let dirPath = path.join(dir, f);
    let isDirectory = fs.statSync(dirPath).isDirectory();
    isDirectory ? walkDir(dirPath, callback) : callback(path.join(dir, f));
  });
}

function processFile(filePath) {
  if (!filePath.endsWith('.ts') && !filePath.endsWith('.tsx')) return;

  let content = fs.readFileSync(filePath, 'utf8');
  let originalContent = content;

  // 1. catch (error: any) -> catch (error: unknown)
  // And replace error.message with (error instanceof Error ? error.message : "Error desconocido")
  if (content.includes('catch (error: any)')) {
    content = content.replace(/catch \(error: any\)/g, 'catch (error: unknown)');
    // replace `error.message` with `(error instanceof Error ? error.message : "Error desconocido")` but only in simple cases
    // actually safer to just do `error instanceof Error ? error.message : String(error)`
    content = content.replace(/error\.message/g, '(error instanceof Error ? error.message : "Error desconocido")');
  }

  if (content.includes('catch (e: any)')) {
    content = content.replace(/catch \(e: any\)/g, 'catch (e: unknown)');
    content = content.replace(/e\.message/g, '(e instanceof Error ? e.message : "Error desconocido")');
  }

  if (content.includes('catch (err: any)')) {
    content = content.replace(/catch \(err: any\)/g, 'catch (err: unknown)');
    content = content.replace(/err\.message/g, '(err instanceof Error ? err.message : "Error desconocido")');
  }

  // 2. React.FormEvent
  if (content.includes('onSubmit(e: any)')) {
    content = content.replace(/onSubmit\(e: any\)/g, 'onSubmit(e: React.FormEvent<HTMLFormElement>)');
  }
  if (content.includes('async function (e: any)')) { // NextJS forms might use actions
    content = content.replace(/\(e: any\)/g, '(e: React.FormEvent<HTMLFormElement>)');
  }

  // 3. prevState: any in server actions
  if (content.includes('prevState: any')) {
    // Keep it generic since it's Next.js standard for useFormState to be generic or any
    content = content.replace(/prevState: any/g, 'prevState: unknown');
  }

  if (content !== originalContent) {
    fs.writeFileSync(filePath, content, 'utf8');
    console.log('Fixed', filePath);
  }
}

walkDir('./src', processFile);

"use server";

import { AttendeesService } from "@/services/attendees.service";
import { revalidatePath } from "next/cache";

import { getSession } from "@/lib/auth";
import { uploadPaymentScreenshot } from "@/lib/supabase";
import { join } from "path";
import { mkdirSync } from "fs";

export async function registerForEvent(formData: FormData) {
  const eventId = formData.get("eventId") as string;
  const name = formData.get("name") as string;
  const phone = formData.get("phone") as string;
  const attendeeType = (formData.get("attendeeType") as "estudiante" | "foraneo") || "estudiante";
  const paymentReference = formData.get("paymentReference") as string | undefined;
  const screenshot = formData.get("screenshot") as File | null;

  try {
    const session = await getSession();
    if (!session) {
      throw new Error("Debes iniciar sesión para registrarte en el evento.");
    }

    if (session.role !== "user") {
      throw new Error("Solo los asistentes regulares pueden registrarse en los eventos. Tu cuenta tiene rol administrativo.");
    }

    // Usamos el email seguro de la sesión en lugar del formulario
    const email = session.email as string;
    const userId = session.userId as string;

    let screenshotUrl: string | null = null;
    if (screenshot && screenshot.size > 0) {
      try {
        screenshotUrl = await uploadPaymentScreenshot(screenshot, "reg-" + Date.now());
      } catch (e) {
        console.error("Supabase error, falling back", e);
      }

      if (!screenshotUrl) {
        const arrayBuffer = await screenshot.arrayBuffer();
        const buffer = Buffer.from(arrayBuffer);
        const fileName = `payment_reg_${Date.now()}.webp`;
        const uploadDir = join(process.cwd(), "public", "uploads", "payments");

        try {
          mkdirSync(uploadDir, { recursive: true });
        } catch (e) {}

        const filePath = join(uploadDir, fileName);

        const sharp = (await import("sharp")).default;
        await sharp(buffer)
          .resize(800, null, { withoutEnlargement: true })
          .webp({ quality: 80 })
          .toFile(filePath);

        screenshotUrl = `/uploads/payments/${fileName}`;
      }
    }

    const newAttendee = await AttendeesService.registerAttendee({ eventId, name, email, phone, userId, attendeeType, paymentReference, paymentScreenshotUrl: screenshotUrl });
    revalidatePath(`/events/[slug]`, "page");
    revalidatePath(`/faculty-admin/events/[id]/attendees`, "page");
    return { success: true, ticketToken: newAttendee.ticketToken };
  } catch (error: unknown) {
    return { error: (error instanceof Error ? error.message : "Error desconocido") };
  }
}

export async function confirmPayment(attendeeId: string, eventId: string) {
  try {
    const session = await getSession();
    if (!session || !session.userId) throw new Error("Unauthorized");

    await AttendeesService.confirmPayment(attendeeId, session.userId as string);
    revalidatePath(`/faculty-admin/events/${eventId}/attendees`);
    return { success: true };
  } catch (error: unknown) {
    return { error: (error instanceof Error ? error.message : "Error desconocido") };
  }
}

export async function manualRegisterByAdmin(formData: FormData) {
  const eventId = formData.get("eventId") as string;
  const name = formData.get("name") as string;
  const email = formData.get("email") as string;
  const phone = formData.get("phone") as string;
  const attendeeType = (formData.get("attendeeType") as "estudiante" | "foraneo") || "estudiante";

  // As it is manual by admin, we can set it as confirmado immediately if desired, or let them choose.
  const statusRaw = formData.get("status") as "registrado" | "confirmado" | "pago_pendiente";
  const status = statusRaw || "confirmado";

  try {
    await AttendeesService.registerAttendee({ eventId, name, email, phone, status, attendeeType });
    revalidatePath(`/faculty-admin/events/${eventId}/attendees`);
    return { success: true };
  } catch (error: unknown) {
    return { error: (error instanceof Error ? error.message : "Error desconocido") };
  }
}

"use server";

import { db } from "@/db";
import { eventRequests } from "@/db/schema";
import { EventRequestMetadataSchema, type EventRequestMetadata } from "@/validations/requests";
import { getSession } from "@/lib/auth";

export async function createEventRequest(
  eventId: string, 
  requestType: "soporte_academico" | "patrocinio" | "cobertura_prensa" | "derechos_transmision", 
  metadataRaw: any
) {
  const session = await getSession();
  if (!session) {
    throw new Error("No estás autenticado.");
  }

  // Zod Validation (Fail-Fast execution security)
  const validationResult = EventRequestMetadataSchema.safeParse(metadataRaw);

  if (!validationResult.success) {
    throw new Error(`Datos inválidos: ${validationResult.error.message}`);
  }

  const metadata = validationResult.data as EventRequestMetadata;

  // Insert into DB
  const [newRequest] = await db.insert(eventRequests).values({
    eventId,
    requestType,
    metadata
  }).returning();

  return newRequest;
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/Button";
import { useRouter } from "next/navigation";

export default function CleanupDatabasePage() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [confirmText, setConfirmText] = useState("");
  const [targetType, setTargetType] = useState<"all" | "events" | "attendees" | "seed">("all");

  const handleCleanup = async () => {
    if (confirmText !== "LIMPIAR") {
      setMessage("Debes escribir LIMPIAR para confirmar.");
      return;
    }

    setLoading(true);
    setMessage("");

    try {
      const res = await fetch("/api/admin/cleanup", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ type: targetType })
      });

      if (!res.ok) {
        throw new Error("Error al limpiar la base de datos.");
      }

      setMessage("Limpieza ejecutada exitosamente.");
      setConfirmText("");
    } catch (e: unknown) {
      setMessage((e instanceof Error ? e.message : "Error desconocido") || "Error desconocido.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-fade-in">
      <div>
        <h1 className="font-headline-lg text-university-blue mb-2 text-3xl">Mantenimiento de Base de Datos</h1>
        <p className="text-on-surface-variant text-body-md">
          Herramienta de limpieza manual. Útil para eliminar datos de prueba garantizando el orden correcto de llaves foráneas.
        </p>
      </div>

      <div className="bg-surface-white rounded-3xl border border-error/20 shadow-sm p-8 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-error"></div>

        <h2 className="font-title-lg text-error mb-4 flex items-center gap-2">
          <span className="material-symbols-outlined">warning</span>
          Zona de Peligro
        </h2>

        <p className="text-on-surface-variant text-sm mb-6">
          Esta acción no se puede deshacer. Por favor, selecciona cuidadosamente qué tipo de datos deseas limpiar. 
          El sistema se encargará de eliminar los registros respetando la jerarquía para evitar errores de restricción de clave foránea.
        </p>

        <div className="space-y-6">
          <div>
            <label className="block font-title-sm text-university-blue mb-2">Selecciona qué limpiar:</label>
            <select 
              value={targetType}
              onChange={(e) => setTargetType(e.target.value as any)}
              className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-error bg-surface-container-lowest"
            >
              <option value="attendees">Solo Asistentes y Logs (Mantener Eventos)</option>
              <option value="events">Eventos, Asistentes y Solicitudes</option>
              <option value="all">Limpieza Parcial (Borra todo, excepto Universidades, Categorías y Facultades)</option>
              <option value="seed">Limpieza Total / Seed (Borra TODO en la BD excepto superadmin)</option>
            </select>
          </div>

          <div>
            <label className="block font-title-sm text-university-blue mb-2">
              Escribe <strong className="text-error">LIMPIAR</strong> para confirmar
            </label>
            <input 
              type="text" 
              value={confirmText}
              onChange={(e) => setConfirmText(e.target.value)}
              placeholder="LIMPIAR"
              className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-error bg-surface-container-lowest" 
            />
          </div>

          {message && (
            <div className={`p-4 rounded-xl text-sm font-bold ${message.includes("exitosa") ? "bg-success/10 text-success" : "bg-error/10 text-error"}`}>
              {message}
            </div>
          )}

          <div className="pt-4 border-t border-outline-variant/50 flex justify-end">
            <button 
              onClick={handleCleanup}
              disabled={loading || confirmText !== "LIMPIAR"}
              className="px-6 py-3 bg-error text-white font-bold rounded-xl hover:bg-error/90 disabled:opacity-50 transition-colors flex items-center gap-2 shadow-sm"
            >
              <span className="material-symbols-outlined">delete_forever</span>
              {loading ? "Procesando..." : "Ejecutar Limpieza"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { EventTimePicker } from "@/components/EventTimePicker";

export default function EditEventPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const [initialData, setInitialData] = useState<any>(null);
  const [tenants, setTenants] = useState<{id: string, name: string}[]>([]);
  const [spaces, setSpaces] = useState<{id: string, name: string}[]>([]);
  const [selectedTenant, setSelectedTenant] = useState("");

  useEffect(() => {
    fetch(`/api/events/${id}`).then(r => r.json()).then(data => {
      // Local time formatting for datetime-local input
      if (data.date) {
        const d = new Date(data.date);
        const tzOffset = d.getTimezoneOffset() * 60000; 
        const localISOTime = (new Date(d.getTime() - tzOffset)).toISOString().slice(0, 16);
        data.date = localISOTime;
      }
      setInitialData(data);
      setSelectedTenant(data.tenantId);
    });
    fetch('/api/tenants').then(r => r.json()).then(setTenants);
  }, [id]);

  useEffect(() => {
    if (!selectedTenant) return;
    fetch(`/api/spaces?tenantId=${selectedTenant}`).then(r => r.json()).then(data => {
      setSpaces(Array.isArray(data) ? data : []);
    });
  }, [selectedTenant]);

  async function onSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setLoading(true);
    setErrorMsg("");

    const formData = new FormData(e.currentTarget);
    if (!formData.get("price")) formData.set("price", "FREE");

    try {
      const res = await fetch(`/api/events/${id}`, {
        method: "PUT",
        body: formData,
      });
      if (!res.ok) {
        const errorData = await res.json();
        throw new Error(errorData.error || "Error actualizando");
      }
      router.push("/admin/events");
      router.refresh();
    } catch (err: unknown) {
      console.error(err);
      setErrorMsg((err instanceof Error ? err.message : "Error desconocido"));
    } finally {
      setLoading(false);
    }
  }

  if (!initialData) return <div className="p-8 text-center text-on-surface-variant">Cargando datos...</div>;

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in">
      <div>
        <h1 className="font-headline-lg text-university-blue mb-2 text-3xl">Editar Evento</h1>
        <p className="text-on-surface-variant text-body-md">Modifica horarios y detalles.</p>
      </div>

      <div className="bg-surface-white rounded-3xl border border-outline-variant shadow-sm p-8">
        {errorMsg && (
          <div className="mb-6 p-4 bg-error/10 border border-error text-error rounded-xl">
            <strong>Atención:</strong> {errorMsg}
          </div>
        )}
        <form onSubmit={onSubmit} className="space-y-6">
          <div>
            <label className="block font-title-sm text-university-blue mb-2">Título del Evento</label>
            <input name="title" defaultValue={initialData.title} required type="text" className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest" />
          </div>

          <EventTimePicker initialDate={initialData.date} initialDuration={initialData.duration} />

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block font-title-sm text-university-blue mb-2">Facultad</label>
              <select 
                name="tenantId" 
                required 
                value={selectedTenant}
                onChange={e => setSelectedTenant(e.target.value)}
                className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest"
              >
                {tenants.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
              </select>
            </div>
            <div>
              <label className="block font-title-sm text-university-blue mb-2">Espacio Físico</label>
              <select name="spaceId" defaultValue={initialData.spaceId} required disabled={!selectedTenant || spaces.length === 0} className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest">
                {spaces.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
          </div>

          <div>
            <label className="block font-title-sm text-university-blue mb-2">Foto / Banner (Opcional, dejar en blanco para mantener la actual)</label>
            <input name="image" type="file" accept="image/jpeg, image/png, image/webp" className="w-full px-4 py-2 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest file:mr-4 file:py-1 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-university-blue file:text-white hover:file:bg-innovation-purple cursor-pointer text-sm" />
            <p className="text-xs text-on-surface-variant mt-1">Máximo 5MB (JPG, PNG, WEBP)</p>
            {initialData.imageUrl && (
              <div className="mt-2">
                <p className="text-xs text-on-surface-variant mb-1">Imagen actual:</p>
                <img src={initialData.imageUrl} alt="Current" className="w-32 h-auto rounded-lg border border-outline-variant" />
              </div>
            )}
          </div>


          <div>
            <label className="block font-title-sm text-university-blue mb-2">Descripción</label>
            <textarea name="description" defaultValue={initialData.description || ""} rows={3} className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest" />
          </div>

          <div className="flex justify-end gap-4 pt-4 border-t border-outline-variant/50">
            <Button type="button" variant="ghost" onClick={() => router.back()}>Cancelar</Button>
            <Button type="submit" variant="primary" disabled={loading}>{loading ? "Validando..." : "Actualizar Evento"}</Button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { Html5Qrcode } from "html5-qrcode";

type ScanStatus = "idle" | "loading" | "success" | "duplicate" | "error";

export default function ScannerPage() {
  const [status, setStatus] = useState<ScanStatus>("idle");
  const [message, setMessage] = useState("");
  const [details, setDetails] = useState<any>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [cameraError, setCameraError] = useState("");

  const scannerRef = useRef<Html5Qrcode | null>(null);
  const isProcessingRef = useRef(false);

  useEffect(() => {
    // Inicializar la instancia base (sin arrancar la cámara aún)
    scannerRef.current = new Html5Qrcode("reader");

    return () => {
      // Limpieza en caso de desmontaje del componente
      if (scannerRef.current && scannerRef.current.isScanning) {
        scannerRef.current.stop().catch(console.error);
      }
    };
  }, []);

  const startScanning = async () => {
    if (!scannerRef.current) return;
    setCameraError("");

    try {
      await scannerRef.current.start(
        { facingMode: "environment" },
        { fps: 10, qrbox: { width: 250, height: 250 } },
        async (decodedText) => {
          // Prevenir múltiples lecturas consecutivas mientras procesamos
          if (isProcessingRef.current) return;

          isProcessingRef.current = true;
          setStatus("loading");

          try {
            const res = await fetch('/api/tickets/validate', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ token: decodedText })
            });

            const data = await res.json();

            if (res.status === 200) {
              setStatus("success");
              setMessage("ACCESO PERMITIDO");
              setDetails(data.attendee);
            } else if (res.status === 409) {
              setStatus("duplicate");
              setMessage("TICKET YA ESCANEADO");
              setDetails({ time: data.scannedAt });
            } else {
              setStatus("error");
              setMessage(data.error || "TICKET INVÁLIDO");
              setDetails(null);
            }
          } catch (err) {
            setStatus("error");
            setMessage("ERROR DE CONEXIÓN");
            setDetails(null);
          }

          // Esperar unos segundos antes de permitir otra lectura
          setTimeout(() => {
            setStatus("idle");
            setMessage("");
            setDetails(null);
            isProcessingRef.current = false;
          }, 3500);
        },
        (error) => {
          // Ignorar los errores frecuentes de "código no encontrado" frame por frame
        }
      );
      setIsScanning(true);
    } catch (err) {
      console.error("Error iniciando cámara:", err);
      setCameraError("No se pudo acceder a la cámara. Verifica los permisos de tu navegador.");
    }
  };

  const stopScanning = async () => {
    if (scannerRef.current && scannerRef.current.isScanning) {
      try {
        await scannerRef.current.stop();
        setIsScanning(false);
        setStatus("idle");
        isProcessingRef.current = false;
      } catch (err) {
        console.error("Error deteniendo cámara:", err);
      }
    }
  };

  return (
    <div className="flex flex-col animate-fade-in">
      <div className="mb-8">
        <h1 className="font-headline-lg text-headline-lg text-university-blue">Escáner de Accesos</h1>
        <p className="text-on-surface-variant mt-2 font-body-md max-w-2xl">
          Verifica la autenticidad de las entradas escaneando el código QR. El sistema registrará la asistencia automáticamente.
        </p>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">
        <div className="w-full lg:w-[500px] bg-surface-white rounded-3xl overflow-hidden shadow-xl border border-outline-variant relative flex flex-col">

          {/* Overlay Status */}
          {status !== "idle" && (
            <div className={`absolute inset-0 z-50 flex flex-col items-center justify-center text-center p-8 transition-colors duration-300
              ${status === 'loading' ? 'bg-surface-white/90 backdrop-blur-sm' : ''}
              ${status === 'success' ? 'bg-green-500 text-white' : ''}
              ${status === 'duplicate' ? 'bg-academic-gold text-university-blue' : ''}
              ${status === 'error' ? 'bg-error text-white' : ''}
            `}>
              {status === 'loading' ? (
                <div className="animate-spin rounded-full h-12 w-12 border-t-4 border-b-4 border-university-blue mb-4"></div>
              ) : (
                <>
                  <span className="material-symbols-outlined text-6xl mb-4">
                    {status === 'success' ? 'check_circle' : status === 'duplicate' ? 'warning' : 'cancel'}
                  </span>
                  <h2 className="font-headline-md text-3xl font-bold uppercase tracking-tight leading-tight mb-4">
                    {message}
                  </h2>
                  {status === 'success' && details && (
                    <div className="bg-black/10 p-4 rounded-xl w-full text-left font-body-md mt-4">
                      <p className="text-sm opacity-80 uppercase tracking-wider font-bold">Asistente</p>
                      <p className="text-xl font-bold mb-2">{details.name}</p>
                      <p className="text-sm opacity-80 uppercase tracking-wider font-bold">Tipo</p>
                      <p className="font-bold">{details.type}</p>
                    </div>
                  )}
                  {status === 'duplicate' && (
                    <div className="bg-black/10 p-4 rounded-xl w-full text-left font-body-md mt-4">
                      <p className="font-bold text-sm">Este código ya fue validado en el sistema.</p>
                    </div>
                  )}
                </>
              )}
            </div>
          )}

          {/* Scanner Container */}
          <div className="bg-black flex-1 relative min-h-[350px] flex items-center justify-center">
            {!isScanning && (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-white/50 p-6 text-center z-10">
                <span className="material-symbols-outlined text-6xl mb-4 opacity-50">qr_code_scanner</span>
                <p>La cámara está apagada.</p>
                {cameraError && <p className="text-error mt-2 text-sm">{cameraError}</p>}
              </div>
            )}
            <div id="reader" className="w-full h-full"></div>
          </div>

          {/* Custom Controls */}
          <div className="p-4 bg-surface-container-lowest border-t border-outline-variant flex justify-center gap-4">
            {!isScanning ? (
              <button 
                onClick={startScanning}
                className="flex items-center gap-2 px-6 py-3 bg-university-blue text-white rounded-xl font-bold shadow-md hover:bg-university-blue/90 transition-colors w-full justify-center"
              >
                <span className="material-symbols-outlined">videocam</span>
                Iniciar Escáner
              </button>
            ) : (
              <button 
                onClick={stopScanning}
                className="flex items-center gap-2 px-6 py-3 bg-error text-white rounded-xl font-bold shadow-md hover:bg-error/90 transition-colors w-full justify-center"
              >
                <span className="material-symbols-outlined">videocam_off</span>
                Detener Escáner
              </button>
            )}
          </div>
        </div>

        <div className="flex-1 bg-surface-white rounded-3xl p-8 shadow-sm border border-outline-variant h-fit">
          <h2 className="font-title-lg text-university-blue flex items-center gap-2 mb-6">
            <span className="material-symbols-outlined text-academic-gold">info</span>
            Instrucciones
          </h2>
          <ul className="space-y-4 text-on-surface-variant font-body-md">
            <li className="flex items-start gap-3">
              <span className="material-symbols-outlined text-university-blue mt-0.5">filter_1</span>
              <div>Haz clic en <strong>Iniciar Escáner</strong> y otorga permisos de cámara al navegador si se solicita.</div>
            </li>
            <li className="flex items-start gap-3">
              <span className="material-symbols-outlined text-university-blue mt-0.5">filter_2</span>
              <div>Encuadra el código QR del asistente dentro del marco visible del escáner.</div>
            </li>
            <li className="flex items-start gap-3">
              <span className="material-symbols-outlined text-university-blue mt-0.5">filter_3</span>
              <div>El escáner verificará automáticamente la entrada en nuestra base de datos y te mostrará el resultado visualmente.</div>
            </li>
          </ul>
        </div>
      </div>
    </div>
  );
}

"use client";
import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";

export default function EditSpacePage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [initialData, setInitialData] = useState<any>(null);
  const [tenants, setTenants] = useState<{id: string, name: string}[]>([]);

  useEffect(() => {
    fetch(`/api/spaces/${id}`).then(r => r.json()).then(setInitialData);
    fetch('/api/tenants').then(r => r.json()).then(setTenants);
  }, [id]);

  async function onSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setLoading(true);
    const formData = new FormData(e.currentTarget);
    const data = {
      name: formData.get("name"),
      capacity: parseInt(formData.get("capacity") as string, 10),
      tenantId: formData.get("tenantId"),
    };

    try {
      const res = await fetch(`/api/spaces/${id}`, {
        method: "PUT",
        body: JSON.stringify(data),
        headers: { "Content-Type": "application/json" }
      });
