import { NextResponse } from "next/server";
import { EventsService } from "@/services/events.service";
import { uploadEventImage } from "@/lib/supabase";
import { getSession } from "@/lib/auth";

export async function GET(request: Request, { params }: { params: Promise<{ id: string }> }) {
  try {
    const { id } = await params;
    const event = await EventsService.getEventById(id);
    if (!event) return NextResponse.json({ error: "Not found" }, { status: 404 });
    return NextResponse.json(event);
  } catch (error: unknown) {
    console.error("GET /api/events/[id] Error:", error);
    return NextResponse.json({ error: "Internal Server Error", details: (error instanceof Error ? error.message : "Error desconocido") || String(error) }, { status: 500 });
  }
}

export async function PUT(request: Request, { params }: { params: Promise<{ id: string }> }) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { id } = await params;

    const contentType = request.headers.get("content-type") || "";
    let body: any = {};

    if (contentType.includes("multipart/form-data")) {
      const formData = await request.formData();

      body.title = formData.get("title");
      body.description = formData.get("description");
      if (formData.get("date")) body.date = new Date(formData.get("date") as string);
      if (formData.get("duration")) body.duration = parseInt(formData.get("duration") as string);
      body.price = formData.get("price");
      body.tenantId = formData.get("tenantId");
      body.spaceId = formData.get("spaceId");
      body.paymentPhone = formData.get("paymentPhone");
      body.paymentId = formData.get("paymentId");
      body.paymentBank = formData.get("paymentBank");
      body.managerId = formData.get("managerId");

      const visibility = formData.get("visibility");
      if (visibility) body.visibility = visibility;

      const status = formData.get("status");
      if (status) body.status = status;

      const image = formData.get("image") as File | null;
      if (image && image.size > 0) {
        if (image.size > 5 * 1024 * 1024) {
          return NextResponse.json({ error: "La imagen es demasiado grande (Máximo 5MB)" }, { status: 400 });
        }

        const allowedTypes = ['image/jpeg', 'image/png', 'image/webp'];
        if (!allowedTypes.includes(image.type)) {
          return NextResponse.json({ error: "Formato de imagen inválido. Solo JPG, PNG y WEBP están permitidos." }, { status: 400 });
        }

        const arrayBuffer = await image.arrayBuffer();
        let buffer = Buffer.from(arrayBuffer);

        const fileName = `event-${Date.now()}.webp`;

        const sharp = (await import("sharp")).default;
        buffer = await sharp(buffer)
          .resize(1200, 800, { fit: 'cover', withoutEnlargement: true })
          .webp({ quality: 80 })
          .toBuffer();

        const uploadedUrl = await uploadEventImage(buffer, fileName);
        if (uploadedUrl) {
          body.imageUrl = uploadedUrl;
        }
      }

      // Limpiar propiedades undefined o null que no fueron enviadas (excepto si el cliente quiere borrar algo, pero FormData devuelve string vacío o null si no se envió)
      Object.keys(body).forEach(key => {
        if (body[key] === null || body[key] === undefined) {
          delete body[key];
        }
      });
    } else {
      // Soporte retrocompatible para JSON
      body = await request.json();
      if (body.date) {
        body.date = new Date(body.date);
      }
    }

    const updated = await EventsService.updateEvent(id, body);
    return NextResponse.json(updated);
  } catch (error: unknown) {
    if ((error instanceof Error ? error.message : "Error desconocido")?.includes("CONF_001")) {
      return NextResponse.json({ error: (error instanceof Error ? error.message : "Error desconocido") }, { status: 409 });
    }
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

export async function DELETE(request: Request, { params }: { params: Promise<{ id: string }> }) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { id } = await params;
    await EventsService.deleteEvent(id);
    return new NextResponse(null, { status: 204 });
  } catch (error) {
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/db";
import { attendees, events } from "@/db/schema";
import { eq } from "drizzle-orm";
import { getSession } from "@/lib/auth";
import { uploadPaymentScreenshot } from "@/lib/supabase";
import { join } from "path";
import { mkdirSync } from "fs";

export async function POST(request: Request) {
  try {
    const session = await getSession();
    if (!session) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const formData = await request.formData();
    const attendeeId = formData.get("attendeeId") as string;
    const paymentReference = formData.get("paymentReference") as string;
    const screenshot = formData.get("screenshot") as File | null;

    if (!attendeeId || !paymentReference) {
      return NextResponse.json({ error: "Missing fields" }, { status: 400 });
    }

    // Verify attendee belongs to user
    const attendee = await db.query.attendees.findFirst({
      where: eq(attendees.id, attendeeId),
    });

    if (!attendee || attendee.userId !== session.userId) {
      return NextResponse.json({ error: "Not found or forbidden" }, { status: 404 });
    }

    let screenshotUrl = null;

    if (screenshot && screenshot.size > 0) {
      try {
        // Tratar de subir a Supabase primero
        screenshotUrl = await uploadPaymentScreenshot(screenshot, attendeeId);
      } catch (e) {
        console.error("Supabase error, falling back", e);
      }

      // Fallback local if Supabase fails or is not configured
      if (!screenshotUrl) {
        const arrayBuffer = await screenshot.arrayBuffer();
        const buffer = Buffer.from(arrayBuffer);
        const fileName = `payment_${attendeeId}_${Date.now()}.webp`;
        const uploadDir = join(process.cwd(), "public", "uploads", "payments");

        try {
          mkdirSync(uploadDir, { recursive: true });
        } catch (e) {}

        const filePath = join(uploadDir, fileName);

        const sharp = (await import("sharp")).default;
        await sharp(buffer)
          .resize(800, null, { withoutEnlargement: true }) // Reduce file size
          .webp({ quality: 80 })
          .toFile(filePath);

        screenshotUrl = `/uploads/payments/${fileName}`;
      }
    }

    await db.update(attendees)
      .set({
        paymentReference,
        paymentScreenshotUrl: screenshotUrl,
        // Mantener el estado en pago_pendiente hasta que el admin lo valide
      })
      .where(eq(attendees.id, attendeeId));

    return NextResponse.json({ success: true });

  } catch (error: unknown) {
    console.error("[POST /api/payments]", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/db";
import { attendees, events } from "@/db/schema";
import { eq } from "drizzle-orm";
import { getSession } from "@/lib/auth";

export async function POST(request: Request) {
  try {
    const session = await getSession();
    // Any tenant_admin can verify for their tenant
    if (!session || session.role !== "tenant_admin") {
      return NextResponse.json({ error: "Unauthorized. Solo los administradores de facultad pueden verificar pagos." }, { status: 401 });
    }

    const body = await request.json();
    const attendeeId = body.attendeeId;
    const action = body.action; // 'approve' or 'reject'

    if (!attendeeId || !action) {
      return NextResponse.json({ error: "Missing fields" }, { status: 400 });
    }

    // Verify attendee exists and manager is assigned to this event
    const attendee = await db.query.attendees.findFirst({
      where: eq(attendees.id, attendeeId),
      with: {
        event: true
      }
    });

    if (!attendee) {
      return NextResponse.json({ error: "Attendee not found" }, { status: 404 });
    }

    if (attendee.event.tenantId !== session.tenantId) {
      return NextResponse.json({ error: "Forbidden. No tienes permisos para este evento." }, { status: 403 });
    }

    if (action === 'approve') {
      await db.update(attendees)
        .set({
          status: 'confirmado',
          paymentVerifiedBy: session.userId as string,
          paymentVerifiedAt: new Date()
        })
        .where(eq(attendees.id, attendeeId));
    } else if (action === 'reject') {
      await db.update(attendees)
        .set({
          status: 'registrado', // Or a new status like 'pago_rechazado' if we added it, but fallback to registrado to force them to try again, or clear the reference
          paymentReference: null,
          paymentScreenshotUrl: null
        })
        .where(eq(attendees.id, attendeeId));
    }

    return NextResponse.json({ success: true });

  } catch (error: unknown) {
    console.error("[POST /api/payments/verify]", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

