import Header from "@/components/Header";
import Footer from "@/components/Footer";
import { db } from "@/db";
import { eq, ilike, and, or } from "drizzle-orm";
import { events as eventsSchema, tenants, spaces, universities } from "@/db/schema";
import Link from "next/link";
import Image from "next/image";
import type { Metadata } from "next";
import { findTenantBySlugOrId, findCategoryBySlugOrId } from "@/lib/slug-helpers";
import { categories as categoriesSchema } from "@/db/schema";

export const metadata: Metadata = {
  title: "Explorar Eventos — UniEvents",
  description: "Descubre conferencias, deportes, talleres y más eventos universitarios.",
};

export default async function EventsExplorePage({ searchParams }: { searchParams: Promise<{ faculty?: string, category?: string, q?: string }> }) {
  const { faculty: facultyId, category: categorySlug, q: query } = await searchParams;

  // Resolve faculty from slug or ID
  let resolvedFacultyId: string | undefined;
  let facultyName = "Todas las Facultades";
  if (facultyId) {
    const tenant = await findTenantBySlugOrId(facultyId);
    if (tenant) {
      resolvedFacultyId = tenant.id;
      facultyName = tenant.name;
    }
  }

  // Resolve category
  let resolvedCategoryId: string | undefined;
  let categoryName = "";
  if (categorySlug) {
    const category = await findCategoryBySlugOrId(categorySlug);
    if (category) {
      resolvedCategoryId = category.id;
      categoryName = category.name;
    }
  }

  let whereClause = undefined;
  if (resolvedFacultyId && query) {
    whereClause = and(
      eq(eventsSchema.tenantId, resolvedFacultyId),
      or(
        ilike(eventsSchema.title, `%${query}%`),
        ilike(eventsSchema.description, `%${query}%`)
      )
    );
  } else if (resolvedFacultyId) {
    whereClause = eq(eventsSchema.tenantId, resolvedFacultyId);
  } else if (resolvedCategoryId && query) {
    whereClause = and(
      eq(tenants.categoryId, resolvedCategoryId),
      or(
        ilike(eventsSchema.title, `%${query}%`),
        ilike(eventsSchema.description, `%${query}%`)
      )
    );
  } else if (resolvedCategoryId) {
    whereClause = eq(tenants.categoryId, resolvedCategoryId);
  } else if (query) {
    whereClause = or(
      ilike(eventsSchema.title, `%${query}%`),
      ilike(eventsSchema.description, `%${query}%`),
      ilike(tenants.name, `%${query}%`),
      ilike(universities.name, `%${query}%`)
    );
  }

  const rows = await db
    .select({
      event: eventsSchema,
      tenant: tenants,
      space: spaces,
    })
    .from(eventsSchema)
    .leftJoin(tenants, eq(eventsSchema.tenantId, tenants.id))
    .leftJoin(spaces, eq(eventsSchema.spaceId, spaces.id))
    .leftJoin(universities, eq(tenants.universityId, universities.id))
    .where(whereClause)
    .orderBy(eventsSchema.date);

  const events = rows.map((row) => ({
    ...row.event,
    tenant: row.tenant,
    space: row.space,
  }));

  return (
    <main className="bg-surface">
      <Header />

      <section className="relative pt-32 pb-16 bg-university-blue overflow-hidden min-h-[40vh] flex items-center">
        <div className="absolute inset-0 opacity-10 pointer-events-none">
          <div className="w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-academic-gold via-transparent to-transparent"></div>
        </div>
        <div className="max-w-container-max mx-auto px-margin-desktop relative z-10 w-full">
          <h1 className="font-display-lg text-display-lg text-surface-white mb-4 animate-fade-in">
            Explorar <span className="text-academic-gold">Eventos</span>
          </h1>
          <p className="text-white/80 font-body-lg max-w-2xl animate-fade-in" style={{ animationDelay: "100ms" }}>
            {facultyId 
              ? `Mostrando eventos programados en ${facultyName}.` 
              : categorySlug 
                ? `Explorando eventos en la categoría de ${categoryName}.`
                : "Descubre conferencias, deportes, talleres y más en tu universidad."}
          </p>

          <form className="mt-8 max-w-2xl animate-fade-in flex flex-col sm:flex-row gap-2" style={{ animationDelay: "200ms" }}>
            {facultyId && <input type="hidden" name="faculty" value={facultyId} />}
            {categorySlug && <input type="hidden" name="category" value={categorySlug} />}
            <div className="flex-1 flex items-center bg-white/10 rounded-xl px-4 py-3 border border-white/20 focus-within:border-academic-gold transition-colors">
              <button 
                type="submit" 
                className="flex items-center justify-center p-0 bg-transparent border-none text-white/50 hover:text-academic-gold transition-colors cursor-pointer mr-3"
                title="Buscar"
              >
                <span className="material-symbols-outlined">search</span>
              </button>
              <input 
                type="text" 
                name="q"
                defaultValue={query || ""}
                placeholder="Buscar por título de evento..."
                className="w-full bg-transparent border-none focus:ring-0 text-white placeholder-white/50 text-label-md focus:outline-none"
              />
            </div>
            <button type="submit" className="bg-academic-gold text-university-blue px-6 py-3 rounded-xl font-bold hover:opacity-90 transition-opacity">
              Buscar
            </button>
          </form>
        </div>
      </section>

      <section className="py-20 max-w-container-max mx-auto px-margin-desktop">
        {events.length === 0 ? (
          <div className="py-24 flex flex-col items-center justify-center text-center bg-surface-white rounded-3xl border border-outline-variant shadow-sm">
            <div className="w-20 h-20 bg-surface-container-high rounded-full flex items-center justify-center mb-6">
              <span className="material-symbols-outlined text-outline text-4xl">event_busy</span>
            </div>
            <h3 className="font-title-lg text-university-blue mb-2">No se encontraron eventos</h3>
            <p className="text-on-surface-variant max-w-md mb-6">
              No hay eventos programados que coincidan con tu búsqueda actual {facultyId ? `en ${facultyName}` : categorySlug ? `en la categoría ${categoryName}` : ""}.
            </p>
            {(facultyId || categorySlug || query) && (
              <Link href="/events" className="text-academic-gold font-bold hover:underline">
                Ver todos los eventos
              </Link>
            )}
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {events.map((evt, idx) => {
              const eDate = new Date(evt.date);
              const isFree = evt.price?.toUpperCase() === 'FREE' || evt.price?.toUpperCase() === 'GRATIS' || evt.price === '0';

              const months = ["Ene", "Feb", "Mar", "Abr", "May", "Jun", "Jul", "Ago", "Sep", "Oct", "Nov", "Dic"];
              const monthStr = months[eDate.getMonth()];
              const dayStr = eDate.getDate().toString().padStart(2, '0');
              const timeStr = `${eDate.getHours().toString().padStart(2, '0')}:${eDate.getMinutes().toString().padStart(2, '0')}`;

              return (
                <article
                  key={evt.id}
                  className="bg-surface-white rounded-2xl overflow-hidden shadow-sm border border-outline-variant group hover:shadow-lg transition-all flex flex-col animate-fade-in"
                  style={{ animationDelay: `${(idx % 10) * 50}ms` }}
                >
                  <div className="relative h-56 overflow-hidden bg-surface-container-high">
                    {evt.imageUrl ? (
                      <Image
                        fill
                        sizes="(max-width: 768px) 100vw, 33vw"
                        className="object-cover group-hover:scale-105 transition-transform duration-700"
                        src={evt.imageUrl}
                        alt={evt.title}
                      />
                    ) : (
                      <div className="absolute inset-0 flex items-center justify-center bg-university-blue/5">
                        <span className="material-symbols-outlined text-6xl text-university-blue/20">local_activity</span>
                      </div>
                    )}

                    <div className="absolute top-4 left-4 bg-surface-white rounded-xl p-2 text-center shadow-md border border-outline-variant min-w-[50px] z-10">
                      <span className="block text-university-blue font-bold text-label-sm leading-tight uppercase">
                        {monthStr}
                      </span>
                      <span className="block text-university-blue font-black text-headline-sm leading-none">
                        {dayStr}
                      </span>
                    </div>

                    <div className="absolute top-4 right-4 z-10">
                      <span className="bg-innovation-purple text-white px-3 py-1 rounded-full text-label-sm font-bold shadow-lg truncate max-w-[150px] block">
                        {evt.tenant?.name || "Global"}
                      </span>
                    </div>
                  </div>

                  <div className="p-6 flex-1 flex flex-col">
                    <h3 className="font-title-lg text-title-lg text-university-blue mb-3 group-hover:text-innovation-purple transition-colors line-clamp-2">
                      {evt.title}
                    </h3>

                    <div className="space-y-2 mb-6 flex-1">
                      <p className="flex items-center gap-2 text-on-surface-variant text-label-md">
                        <span className="material-symbols-outlined text-sm">location_on</span>
                        <span className="truncate">{evt.space?.name || "Por definir"}</span>
                      </p>
                      <p className="flex items-center gap-2 text-on-surface-variant text-label-md">
                        <span className="material-symbols-outlined text-sm">schedule</span>
                        {timeStr} ({evt.duration} min)
                      </p>
                    </div>

                    <div className="flex items-center justify-between mt-auto pt-4 border-t border-outline-variant/50">
                      <span
                        className={`font-extrabold text-title-lg ${
                          isFree ? "text-green-600" : "text-university-blue"
                        }`}
                      >
                        {isFree ? "GRATIS" : evt.price}
                      </span>
                      <Link href={`/events/${evt.slug || evt.id}`}>
                        <button className="bg-university-blue text-white px-5 py-2 rounded-lg font-bold hover:bg-innovation-purple transition-colors flex items-center gap-2">
                          Detalles
                          <span className="material-symbols-outlined text-sm">arrow_forward</span>
                        </button>
                      </Link>
                    </div>
                  </div>
                </article>
              );
            })}
          </div>
        )}
      </section>

      <Footer />
    </main>
  );
}

import { db } from "@/db";
import { scanLogs, attendees, events, users, tenants } from "@/db/schema";
import { eq, desc, inArray } from "drizzle-orm";
import { getSession } from "@/lib/auth";
import { redirect } from "next/navigation";
import Link from "next/link";

export default async function AuditLogsPage() {
  const session = await getSession();
  if (!session || session.role !== "tenant_admin" || !session.tenantId) {
    redirect("/login");
  }

  // Get all events for this tenant to filter the logs
  const tenantEvents = await db.query.events.findMany({
    where: eq(events.tenantId, session.tenantId as string),
    columns: { id: true }
  });

  const eventIds = tenantEvents.map(e => e.id);

  let logs: any[] = [];
  if (eventIds.length > 0) {
    logs = await db.query.scanLogs.findMany({
      where: inArray(scanLogs.eventId, eventIds),
      with: {
        event: true,
        attendee: true,
        scanner: true
      },
      orderBy: [desc(scanLogs.scannedAt)],
      limit: 100 // Limit to recent 100 logs for prototype
    });
  }

  return (
    <div className="space-y-8 animate-fade-in">
      <div>
        <h1 className="font-headline-lg text-university-blue mb-2 text-3xl">Auditoría de Acceso</h1>
        <p className="text-on-surface-variant text-body-md">
          Registro visual de escaneos de códigos QR y control de acceso.
        </p>
      </div>

      <div className="bg-surface-white rounded-3xl border border-outline-variant shadow-sm overflow-hidden">
        {logs.length === 0 ? (
          <div className="p-16 flex flex-col items-center justify-center text-center">
            <div className="w-16 h-16 bg-surface-container-high rounded-full flex items-center justify-center mb-4">
              <span className="material-symbols-outlined text-outline text-2xl">history_toggle_off</span>
            </div>
            <h3 className="font-title-md text-university-blue mb-2">Sin registros de auditoría</h3>
            <p className="text-on-surface-variant text-sm max-w-xs">
              Aún no se ha escaneado ningún código QR en los eventos de tu facultad.
            </p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-surface-container-lowest border-b border-outline-variant">
                  <th className="px-6 py-4 text-sm font-bold text-university-blue uppercase tracking-wider">Fecha y Hora</th>
                  <th className="px-6 py-4 text-sm font-bold text-university-blue uppercase tracking-wide">Asistente</th>
                  <th className="px-6 py-4 text-sm font-bold text-university-blue uppercase tracking-wide">Evento</th>
                  <th className="px-6 py-4 text-sm font-bold text-university-blue uppercase tracking-wide">Personal de Acceso (Escaneado por)</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-outline-variant/50">
                {logs.map((log) => (
                  <tr key={log.id} className="hover:bg-surface-container-lowest transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <span className="material-symbols-outlined text-innovation-purple text-lg">qr_code_scanner</span>
                        <span className="text-sm font-mono text-on-surface-variant">
                          {new Date(log.scannedAt).toLocaleString('es-ES', { 
                            day: '2-digit', month: '2-digit', year: 'numeric', 
                            hour: '2-digit', minute: '2-digit', second: '2-digit' 
                          })}
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm font-medium text-on-surface">
                      {log.attendee.name}
                    </td>
                    <td className="px-6 py-4 text-sm text-on-surface-variant">
                      <Link href={`/faculty-admin/events/${log.event.id}/attendees`} className="hover:text-university-blue hover:underline">
                        {log.event.title}
                      </Link>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-sm font-medium text-university-blue">{log.scanner.email}</span>
                        <span className="text-xs text-on-surface-variant bg-surface-container px-2 py-0.5 rounded-full w-fit mt-1">
                          {log.scanner.role === 'access_control' ? 'Control de Acceso' : 'Administrador'}
                        </span>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/Button";
import { EventTimePicker } from "@/components/EventTimePicker";

export default function FacultyEditEventPage({ params }: { params: Promise<{ id: string }> }) {
  const router = useRouter();
  const { id } = use(params);
  const [loading, setLoading] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  const [faculty, setFaculty] = useState<{id: string, name: string} | null>(null);
  const [spaces, setSpaces] = useState<{id: string, name: string, capacity: number}[]>([]);
  const [managers, setManagers] = useState<{id: string, email: string}[]>([]);
  const [eventData, setEventData] = useState<any>(null);

  // 1. Fetch faculty
  useEffect(() => {
    fetch('/api/auth/me')
      .then(r => r.json())
      .then(data => {
        if (data && data.id) {
          setFaculty(data);
        }
      });
  }, []);

  // 2. Fetch spaces when faculty is loaded
  useEffect(() => {
    if (!faculty) return;

    fetch(`/api/spaces?tenantId=${faculty.id}`)
      .then(r => r.json())
      .then(data => {
        if (Array.isArray(data)) setSpaces(data);
      })
      .catch(() => setSpaces([]));

    fetch(`/api/users/managers?role=event_manager`)
      .then(r => r.json())
      .then(data => {
        if (Array.isArray(data)) setManagers(data);
      })
      .catch(() => setManagers([]));
  }, [faculty]);

  // 3. Fetch event data
  useEffect(() => {
    if (!id) return;

    fetch(`/api/events/${id}`)
      .then(r => r.json())
      .then(data => {
        setEventData(data);
      })
      .catch(() => setErrorMsg("No se pudo cargar el evento"));
  }, [id]);

  async function onSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    if (!faculty) return;

    setLoading(true);
    setErrorMsg("");

    const formData = new FormData(e.currentTarget);
    formData.append("tenantId", faculty.id);
    const priceVal = formData.get("price") as string;
    if (!priceVal || priceVal.toUpperCase() === "FREE" || priceVal.toUpperCase() === "GRATIS") {
      formData.set("price", "0");
    } else {
      formData.set("price", priceVal.replace(",", "."));
    }

    try {
      const res = await fetch(`/api/events/${id}`, {
        method: "PUT",
        body: formData,
      });

      if (!res.ok) {
        // Fallback para APIs que no soportan PUT y en su lugar usan PATCH u otro
        // Si tienes problemas de API, ajusta el verbo o verifica /api/events/[id]
        const errorData = await res.json().catch(() => ({}));
        throw new Error(errorData.error || "Error actualizando evento");
      }

      router.push("/faculty-admin/events");
      router.refresh();
    } catch (error: unknown) {
      console.error(error);
      setErrorMsg((error instanceof Error ? error.message : "Error desconocido"));
    } finally {
      setLoading(false);
    }
  }

  if (!eventData) return <div className="p-10 animate-pulse">Cargando...</div>;

  // Formato para datetime-local
  let formattedDate = "";
  if (eventData.date) {
    const d = new Date(eventData.date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    formattedDate = d.toISOString().slice(0, 16);
  }

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in">
      <div>
        <h1 className="font-headline-lg text-university-blue mb-2 text-3xl">Editar Evento</h1>
        <p className="text-on-surface-variant text-body-md">
          Modifica los detalles del evento <span className="font-bold text-academic-gold">{eventData.title}</span>
        </p>
      </div>

      <div className="bg-surface-white rounded-3xl border border-outline-variant shadow-sm p-8">
        {errorMsg && (
          <div className="mb-6 p-4 bg-error/10 border border-error text-error rounded-xl">
            <strong>Atención:</strong> {errorMsg}
          </div>
        )}

        <form onSubmit={onSubmit} className="space-y-6">
          <div>
            <label className="block font-title-sm text-university-blue mb-2">Título del Evento</label>
            <input name="title" defaultValue={eventData.title} required type="text" className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest" />
          </div>

          <EventTimePicker initialDate={formattedDate} initialDuration={eventData.duration} />

          <div>
            <label className="block font-title-sm text-university-blue mb-2">Precio de Entrada</label>
            <input name="price" defaultValue={eventData.price} type="text" className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest" placeholder="0 para gratis, o 10.50" />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block font-title-sm text-university-blue mb-2">Espacio Físico</label>
              <select name="spaceId" defaultValue={eventData.spaceId} required disabled={spaces.length === 0} className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest disabled:opacity-50">
                <option value="">{spaces.length === 0 ? "-- Sin Espacios --" : "-- Selecciona un Espacio --"}</option>
                {spaces.map(s => <option key={s.id} value={s.id}>{s.name} (Capacidad: {s.capacity})</option>)}
              </select>
            </div>
            <div>
              <label className="block font-title-sm text-university-blue mb-2">Foto / Banner (Opcional, dejar en blanco para mantener la actual)</label>
              <input name="image" type="file" accept="image/jpeg, image/png, image/webp" className="w-full px-4 py-2 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest file:mr-4 file:py-1 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-university-blue file:text-white hover:file:bg-innovation-purple cursor-pointer text-sm" />
              <p className="text-xs text-on-surface-variant mt-1">Máximo 5MB (JPG, PNG, WEBP)</p>
              {eventData.imageUrl && (
                <div className="mt-2">
                  <p className="text-xs text-on-surface-variant mb-1">Imagen actual:</p>
                  <img src={eventData.imageUrl} alt="Current" className="w-32 h-auto rounded-lg border border-outline-variant" />
                </div>
              )}
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-outline-variant/50">
            <div>
              <label className="block font-title-sm text-university-blue mb-2">Visibilidad</label>
              <select name="visibility" defaultValue={eventData.visibility || "publico"} className="w-full px-4 py-3 border border-outline-variant rounded-xl focus:outline-none focus:ring-2 focus:ring-academic-gold bg-surface-container-lowest">
                <option value="publico">Público</option>
