import { SignJWT, jwtVerify } from "jose";
import { cookies } from "next/headers";

const secretKey = process.env.JWT_SECRET || "uni-events-super-secret-key-32-chars!!";
const encodedKey = new TextEncoder().encode(secretKey);

export async function encrypt(payload: any) {
  return new SignJWT(payload)
    .setProtectedHeader({ alg: "HS256" })
    .setIssuedAt()
    .setExpirationTime("7d")
    .sign(encodedKey);
}

export async function decrypt(session: string | undefined = "") {
  if (!session) return null;
  try {
    const { payload } = await jwtVerify(session, encodedKey, {
      algorithms: ["HS256"],
    });
    return payload;
  } catch (error) {
    return null;
  }
}

export async function getSession() {
  const cookieStore = await cookies();
  const sessionCookie = cookieStore.get("session")?.value;
  return await decrypt(sessionCookie);
}

export async function createSession(userId: string, role: string, tenantId?: string | null, email?: string) {
  const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);
  const session = await encrypt({ userId, role, tenantId, email, expiresAt });
  const cookieStore = await cookies();

  cookieStore.set("session", session, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    expires: expiresAt,
    sameSite: "lax",
    path: "/",
  });
}

export async function deleteSession() {
  const cookieStore = await cookies();
  cookieStore.delete("session");
}

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '';

export const supabase = (supabaseUrl && supabaseKey) ? createClient(supabaseUrl, supabaseKey) : null;

export async function uploadPaymentScreenshot(file: File, attendeeId: string): Promise<string | null> {
  if (!supabase) {
    console.warn("Supabase not configured, falling back to local storage or returning null");
    return null; // The API route will fallback to local storage
  }

  try {
    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);
    const fileName = `payment_${attendeeId}_${Date.now()}.webp`;

    const { data, error } = await supabase
      .storage
      .from('payments') // Make sure this bucket exists in Supabase
      .upload(fileName, buffer, {
        contentType: 'image/webp',
        upsert: true
      });

    if (error) {
      console.error("Supabase upload error:", error);
      throw error;
    }

    const { data: publicUrlData } = supabase.storage.from('payments').getPublicUrl(fileName);
    return publicUrlData.publicUrl;
  } catch (err) {
    console.error("Error uploading to Supabase:", err);
    throw err;
  }
}

export async function uploadEventImage(buffer: Buffer, fileName: string): Promise<string | null> {
  if (!supabase) {
    console.warn("Supabase not configured, falling back to local storage or returning null");
    return null;
  }

  try {
    const { data, error } = await supabase
      .storage
      .from('events') // Make sure this bucket exists in Supabase
      .upload(fileName, buffer, {
        contentType: 'image/webp',
        upsert: true
      });

    if (error) {
      console.error("Supabase upload error:", error);
      throw error;
    }

    const { data: publicUrlData } = supabase.storage.from('events').getPublicUrl(fileName);
    return publicUrlData.publicUrl;
  } catch (err) {
    console.error("Error uploading event image to Supabase:", err);
    throw err;
  }
}

import { db } from "@/db";
import { attendees, events } from "@/db/schema";
import { eq, asc, and, sql } from "drizzle-orm";

export class AttendeesService {
  static async registerAttendee(data: { eventId: string; name: string; email: string; phone: string; status?: "registrado" | "confirmado" | "pago_pendiente", userId?: string, attendeeType?: "estudiante" | "foraneo", paymentReference?: string, paymentScreenshotUrl?: string | null }) {
    // Check if event exists
    const event = await db.query.events.findFirst({ 
      where: eq(events.id, data.eventId),
      with: { space: true }
    });
    if (!event) throw new Error("Event not found");

    // Avoid duplicate registration
    if (data.userId) {
      const existing = await db.query.attendees.findFirst({
        where: and(eq(attendees.eventId, data.eventId), eq(attendees.userId, data.userId))
      });
      if (existing) {
        throw new Error("Ya estás registrado en este evento.");
      }
    }

    // Capacity Check
    const capacity = event.capacity ?? event.space?.capacity;
    if (capacity) {
      const attendeesCountResult = await db.execute(sql`SELECT count(*) as count FROM ${attendees} WHERE event_id = ${data.eventId}`);
      const currentCount = Number(attendeesCountResult[0]?.count || 0);
      if (currentCount >= capacity) {
        throw new Error("Lo sentimos, el evento ha alcanzado su capacidad máxima (sold out).");
      }
    }

    // Determine status based on price if not explicitly provided
    let status = data.status;
    if (!status) {
       const isFree = event.price === 'FREE' || event.price === 'GRATIS' || event.price === '0' || !event.price;
       status = isFree ? "confirmado" : "pago_pendiente";
    }

    const [newAttendee] = await db.insert(attendees).values({
      eventId: data.eventId,
      name: data.name,
      email: data.email,
      phone: data.phone,
      status: status,
      userId: data.userId,
      attendeeType: data.attendeeType || "estudiante",
      paymentReference: data.paymentReference,
      paymentScreenshotUrl: data.paymentScreenshotUrl,
    }).returning();

    return newAttendee;
  }

  static async getAttendeesByEvent(eventId: string) {
    return await db.query.attendees.findMany({
      where: eq(attendees.eventId, eventId),
      orderBy: (attendees, { asc }) => [asc(attendees.createdAt)],
    });
  }

  static async confirmPayment(attendeeId: string, verifierId: string) {
    const [updated] = await db.update(attendees)
      .set({ 
        status: "confirmado",
        paymentVerifiedBy: verifierId,
        paymentVerifiedAt: new Date()
      })
      .where(eq(attendees.id, attendeeId))
      .returning();
    return updated;
  }

  static async removeAttendee(attendeeId: string) {
    await db.delete(attendees).where(eq(attendees.id, attendeeId));
  }
}

